import time
import requests

class RateLimitedAPICaller:
    def __init__(self, requests_per_second: float):
        if requests_per_second <= 0:
            raise ValueError("requests_per_second must be a positive number.")
        self.interval_between_requests = 1.0 / requests_per_second
        self.last_request_time = 0.0

    def make_request(self, url: str, method: str = 'GET', **kwargs) -> requests.Response | None:
        current_time = time.monotonic()
        elapsed_since_last_request = current_time - self.last_request_time

        if elapsed_since_last_request < self.interval_between_requests:
            time_to_wait = self.interval_between_requests - elapsed_since_last_request
            time.sleep(time_to_wait)

        try:
            response = requests.request(method, url, **kwargs)
            response.raise_for_status()
            return response
        except requests.exceptions.RequestException:
            return None
        finally:
            self.last_request_time = time.monotonic()
